        }
      },
      "required": [
        "application_id"
      ]
    },
    "example_output": {
      "status": "Pending",
      "days_elapsed": 45,
      "ownership_status": "Non-Compliant",
      "deficiencies": [
        "Discretionary authority reconciliation required"
      ]
    }
  },
  "read_system_logs": {
    "description": "Retrieves the internal audit trail and system logs for a specific application to identify specific regulatory flags, such as the BO Opacity Index or OIG triggers.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string",
          "description": "The unique permit identifier."
        }
      },
      "required": [
        "application_id"
      ]
    },
    "example_output": {
      "logs": [
        {
          "timestamp": "2023-10-01",
          "entry": "Flag: High BO Opacity Index detected; Offshore Ownership profile identified."
        }
      ]
    }
  },
  "resolve_ownership_protocols": {
    "description": "Submits the required beneficial ownership (BO) compliance data and documentation for an application.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string",
          "description": "The unique permit identifier."
        },
        "compliance_documentation": {
          "type": "object",
          "description": "The specific documents and data fields required, which may include Enhanced Due Diligence (EDD) materials."
        }
      },
      "required": [
        "application_id",
        "compliance_documentation"
      ]
    },
    "example_output": {
      "compliance_result": "Verified",
      "status_code": "BO-OK"
    }
  },
  "search_reviewers": {
    "description": "Searches the database of authorized personnel for a reviewer possessing the necessary authority level to handle specific procedural reconciliations.",
    "parameters": {
      "type": "object",
      "properties": {
        "required_authority": {
          "type": "string",
          "description": "The authority type required (e.g., 'Discretionary Authority')."
        }
