      "required": [
        "required_authority"
      ]
    },
    "example_output": {
      "reviewers": [
        {
          "reviewer_id": "USER-101",
          "name": "Sarah Connor",
          "authority": "Discretionary Authority"
        }
      ]
    }
  },
  "execute_discretionary_action": {
    "description": "Applies discretionary authority to resolve procedural gaps. Requires a formal justification of specific length for regulatory audit compliance.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string",
          "description": "The unique permit identifier."
        },
        "reviewer_id": {
          "type": "string",
          "description": "The ID of the personnel authorized to execute this action."
        },
        "justification": {
          "type": "string",
          "description": "A formal text justification (must meet word count requirements identified in deficiencies)."
        }
      },
      "required": [
        "application_id",
        "reviewer_id",
        "justification"
      ]
    },
    "example_output": {
      "reconciliation_success": true,
      "audit_id": "AUTH-8821"
    }
  },
  "update_permit_status": {
    "description": "Updates the status of the permit to 'Issued' or other workflow states after all prerequisites are met.",
    "parameters": {
      "type": "object",
      "properties": {
        "application_id": {
          "type": "string",
          "description": "The unique permit identifier."
        },
        "status": {
          "type": "string",
          "enum": [
            "Issued",
            "Denied",
            "Pending"
          ],
          "description": "The target status."
        }
      },
      "required": [
        "application_id",
        "status"
      ]
    },
    "example_output": {
      "application_id": "APP-909",
      "new_status": "Issued"
    }
  }
}
